INSERT INTO `company` (`name`, `shortName`, `description`, `logo`, `fields`, `id`, `capacity`, `building`, `buildTel`, `tel`, `panels`, `assigned`, `undergrads`) VALUES
('Kent Engineers (Pvt) Ltd', 'kent', 'Kent Engineers (Pvt) Ltd is a ISO 9001 : 2008 certified Mechanical Electrical and Plumbing contractor with 23 years of national and international experience. It is EM1 ranked company for Plumbing, Electrical and Fire (Top Rank by ICTAD). We have proven record of expertise in the design, procurement and installation of Plumbing , Electrical, HVAC, Fire and Gas services for high rise apartments, star class hotels, hospitals, office complexes and many other kind of developments both nationally and internationally. We are also specializing in supply and installation of swimming pool equipment, Sewerage treatment plant equipment, compressed air systems and steam systems.', 'https://fbcdn-sphotos-h-a.akamaihd.net/hphotos-ak-ash3/554638_516761691702752_1956867050_n.jpg', ',CE,EE,MECH,', 15, 36, 'EE Seminar Room', '0710820599', '0719565744', 1, 36, ''),
('Royal Ceramics Lanka PLC', 'rocell', 'Today, Rocell is a fashion icon. Influencing lifestyle and infusing creative thinking; elevating mundane convention into expressions of individualism.\r\n\r\nWith two top-of-the-line tile production facilities, the brand is the quintessential interior market revolutionary, providing aesthetic masterpieces that work flawlessly. The technology, the standards and the artistic maturity that provide for every Rocell tile come from world leaders in their respective fields.\r\n\r\nLocally 43 showrooms carry Rocell''s assortment of designer tiles, while numerous dealerships across 4 continents showcase the products alongside international best brands.\r\n\r\nAn insatiable quest for perfection marks the company''s path. Opening up the country''s first, and one of Asia''s most advance sanitary-ware manufacturing plants, Rocell Bathware is a fine illustration of this pursuit.\r\n\r\nIgniting the design kaleidoscope longing within all of us, Rocell is a channel for distinctiveness, artistic fineness and a catalyst in the interior evolution that is shaping our landscape.', 'https://fbcdn-sphotos-b-a.akamaihd.net/hphotos-ak-frc3/526212_10150807419288377_1766055896_n.jpg', ',CE,ERM,EE,MECH,ME,', 16, 30, 'Madanjeet Center', '0718767330', '0728032710', 1, 30, ''),
('Bharti Airtel Lanka Pvt Ltd', 'airtel', 'Bharti Airtel Lanka is a subsidiary of Bharti Airtel Limited; a global telecommunications company with headquarters in New Delhi, India, currently operating in over 20 countries across Asia and Africa. Bharti Airtel Lanka commenced commercial operations of services in Sri Lanka on January 12, 2009, as the fifth entrant in a highly saturated market, and was the fastest operator to reach 1 million customers in Sri Lanka. As one of Sri Lanka''s largest foreign investors, Airtel has invested over US$ 300 million in Sri Lanka and has achieved island-wide coverage in under two years which has enabled it to emerge as Sri Lanka''s fastest expanding network.', 'https://fbcdn-sphotos-a-a.akamaihd.net/hphotos-ak-prn2/971088_617912608232362_1350325715_n.jpg', ',EE,ENTC,FM,IT,', 17, 18, 'ENTC PG Room', '0717260366,0718538811', '0710161416', 1, 18, ''),
('i-Context Content Convergence (Pvt) Ltd', 'icontext', 'Headquartered in Colombo, Sri Lanka i-Context Content Convergence (Pvt) Limited, was founded by a group of entrepreneurs who have much experience in the telecom convergence and e-Learning. Our mission is to make it possible for anyone to access on-demand digital lifestyle services, whether it be learning or infotainment- anytime, anyplace and on any device. We at i-Context provide software solutions to enable network operators, content providers and consumers to collaborate on a three screen strategy, platform and connected infrastructure, to support digital lifestyle services via Web, IPTV and Mobile.', 'http://i-context.net/images/imgLogo.gif', ',CSE,IT,', 12, 0, 'None', '0715465178', '0000000000', 1, 0, ''),
('Glide(Pvt) Ltd', 'glide', 'GLIDE (PVT) LTD. is a registered Energy Services Company (ESCO) by the Sustainable Energy Authority of Sri Lanka. GLIDE has been in operation since 2004. The company staff comprises a group of environmental, social and engineering professionals with state-of-the-art knowledge on energy efficiency solutions, management and implementation. In addition we draw on an extensive pool of external consultants both domestic and foreign to cater to your specific company needs.', 'http://fbcdn-sphotos-e-a.akamaihd.net/hphotos-ak-ash2/430117_345950158762375_1477945427_n.jpg', ',CPE,CE,EE,FM,MECH,', 13, 13, 'CERC 302', '0716753144', '0718927049', 1, 13, ''),
('Holcim (Lanka) Ltd', 'holcim', 'Holcim Lanka is a part of the global Holcim group. Being the market leader in the cement industry, the company focuses on Economic, Social and Environmental performance along the triple bottom line of sustainable development. The company currently operates one fully integrated cement plant in Puttalam, while also operating a grinding plant in Galle. A new packing unit is planned for Trincomalee, for better customer focus and coverage. Also accessible for imported cement is the Ambuja Terminal, now called Galle Cement Terminal if additional cement is required', 'http://www.iaeste.lk/wp-content/uploads/2012/02/current%20employees/Holcim-logo.gif', ',CE,ERM,', 14, 18, 'Madanjeet Center', '0718767330', '0779135180', 1, 18, ''),
('Wavenet International (Pvt) Ltd', 'wavenet', 'Company Overview Deploying products and solutions used by over 60 million people across South Asia and Asia Pacific, WaveNET''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs expertise in network based multimedia enhanced communication at wireless and wireline carriers worldwide has rooted the company firmly among the world''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs leaders in software solutions. Armed with the latest enabling technology and equipped with reliable and scalable solutions designed for Telco''s, the most demanding traffic requirements are catered to.   Embracing a standards based open software architectural platforming the telecommunications network, mobile, messaging and voice-over internet protocol (VoIP), the business is poised to echo subscriber needs and enrich user experience. Business Activities 3G Video VAS Messaging Mobile Marketing IVR', 'http://img.b8cdn.com/images/uploads/user_logos/59/1531159_20130718101027.gif', ',CSE,EE,ENTC,', 18, 25, 'ERM Seminar Room', '0714155561', '0719799887', 1, 16, ''),
('South Asia Gateway Terminals (Pvt) Ltd', 'sagt', 'Sri Lanka is an island in the Indian Ocean and located to the south of the Indian sub-continent. The Port of Colombo, located in the South-West corner of the island is rated amongst the Top Container ports in the world. South Asia Gateway Termianls (Pvt) Ltd., better known as SAGT is on a 30 year B.O.T. and is owned by a consortium of local and international establishments of repute. The terminal is located in the port of Colombo at the renowned and historic Queen Elizabeth Quay. The portÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs natural geographic location is strategically positioned on the main East-West shipping route, linking the Far East with Africa, Europe, and the East Coast of the US, providing ideal connections to the trade in the Indian sub-continent. This makes the Port of Colombo a superb strategic hub. In 1999 SAGT set out to conquer its quest of setting benchmark standards in terms of service excellence, productivity, efficiency and consistency. Today SAGT peruses its commitment in maintaining international standards and its position as ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂThe Transhipment Hub of TomorrowÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs WorldÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ', 'http://www.sagt.com.lk/images/SAGT_Main_Logo.jpg', ',EE,MECH,TLM,', 19, 0, 'Sumanadasa Building', '0710820599', '0726170392', 1, 0, ''),
('Consulting Engineers & Contractors (Pvt) Ltd', 'CEC', 'CONSULTING ENGINEERS & CONTRACTORS (PVT) LTD, commonly known as CEC, is a major construction company in Sri Lanka, with C1 ICTAD classification as a major road contractor for over a decade. Over the last 15 years CEC has grown from being a small independent contractor to a major construction and road development company, and is now recognized as a dependable contractor with a very high rating for delivering projects with great quality and on-time.\r\n\r\n\r\nThe company''s relentless drive towards achieving quality of service saw the company achieve ISO 9001-2000 and ISO 9001-2008 certification, which established CEC''s credentials as a construction company in Sri Lanka which is quality conscious and customer centric. CEC has successfully completed development of 500 kilometers of road in Sri Lanka thus far, with over 200 km in 2009/2010 alone.\r\n\r\nOne of the key success factors being that CEC owns an extensive inventory of plant and machinery used in road development projects, with 6 crusher plants, and 2 Asphalt plants along with 6 quarries, ensuring speedy supply of quality raw material to its work sites.\r\n', 'http://www.psssoftwaresolutions.com/images/customers/cec.png', ',CE,ERM,ME,MECH,QS,TLM,', 20, 24, 'CERC 401', '0716753144', '0715296624', 1, 24, ''),
('Hirdaramani Group ', 'Hirdaramani', 'From the beginning as a single retail store in the heart of Colombo''s commercial district, the Hirdaramani Group has diversified in recent years to encompass the apparel, leisure, power, information technology and retail industries, stamping the respected Hirdaramani standard on each. Today Hirdaramani Group boasts a rich and diverse heritage with over 30,000 employees spread across six countries and six industries, each adding their own thread to the company''s story.', 'http://www.hirdaramani.com/images/logo_for_company.png', ',CPE,CSE,IT,FD,TC,', 21, 15, 'TM Lec room', '0715297460', '0711477956', 1, 15, ''),
('Atrenta Lanka (Pvt) Ltd', 'Atrenta', 'Atrenta is an electronic design automation (EDA) company that develops software to automate design of the most complex system-on-chip (SoC) designs in the world.  These are the chips that power advanced products in markets such as consumer electronics, cloud computing, hand-held communications and advanced automotive systems -ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ virtually every SoC built today uses our software.\r\n \r\nAtrenta is the largest private EDA company in the industry and you will be developing highly complex software for companies such as: Altera, Cisco, Qualcomm, TSMC, Fujitsu, LG, NVIDIA, STMicroelectronics, Texas Instruments, AMD and many others.', 'http://www.dac.com/App_Content/images/50/Atrenta_spyglass_rgb_logo.jpg', ',CSE,ENTC,IT,', 22, 15, 'IT Lec Room', '0715779877,0772980726', '0777751825', 1, 11, ''),
('Etisalat Lanka (PVT) LTD', 'etisalat', 'Etisalat is fully owned and operated by the Emirates Telecommunication Corporation in UAE. It has extended operations in Egypt and Saudi Arabia in the Middle East and further into Asian markets such as Pakistan, Afghanistan and Sri Lanka, recording over 167 million subscribers across 16 countries offering opportunities for synergy with our other operations in the region. \r\n\r\n Etisalat is consistently providing not only the widest coverage and an unprecedented service, but also a host of other Value Added Services. We are dynamic and treat our customers as our own, and consider customer service as our first priority.', 'http://upload.wikimedia.org/wikipedia/en/e/e7/Etisalat_Lanka_logo.svg', ',CE,CSE,ENTC,IT,', 23, 36, 'ENTC 3.5', '0717260366,0718538814', '0712622603', 1, 36, ''),
('Ceylon Tobacco Company PLC', 'CTC', 'Ceylon Tobacco Company PLC engages in the manufacture, marketing, and export of cigarettes. It offers its products primarily under the Dunhill, Pall Mall, John Player Gold Leaf, Three Roses, Capstan, and Four Aces brand names. The company was incorporated in 1932 and is headquartered in Colombo. Ceylon Tobacco Company PLC is a subsidiary of British American Tobacco Holdings (Sri Lanka) BV.\r\n', 'http://synergyy.com/wp-content/uploads/2011/07/Ceylon-Tobacco-Company-PLC.jpg', ',CPE,CE,ERM,EE,FM,ME,MECH,TLM,', 24, 50, 'NCSLB', '0715507040', '0711873774', 1, 50, ''),
('Maga Engineering (Pvt) Ltd', 'Maga', 'Maga strives to maintain a diverse workplace that promotes mutual respect and professionalism free from all forms of intimidation, harassment violence thus having a positive influence on creativity, satisfaction and motivation whilst empowering and enhancing the performance of the employees.', 'http://www.maga.lk/wp-content/themes/maga/images/logo.gif', ',CE,QS,ME,', 25, 50, 'CE 303', '0713601629', '0719278764', 1, 50, ''),
('Hayleys Group of Companies', 'hayleys', 'Embracing innovation and entrepreneurship, we''ve added value for people and businesses across the country and beyond. It is this spirit that has characterised our growth and the building of a strong and successful enterprise that is active in local and global markets. In addition to Sri Lanka, Hayleys today has manufacturing facilities in Indonesia and Thailand, and marketing operations in Australia, India, Bangladesh, Italy, Japan, The Netherlands, UK and USA. The Group accounts for 3.17% of Sri Lanka''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs export income, and 4.5% of tea and 2.2% of rubber production.\r\n\r\nWe see our diversity as a vital strategic advantage; from cutting edge purification solutions and patented products to innovative business processes and supply chain management, our people share ideas across departments and sectors of business.\r\n\r\n\r\nAt Hayleys, we believe that people make the difference between a good organization and an excellent one. The aspirations, competencies and commitment of our people are at the heart of all our achievements. Hayleys Group, the Sri Lankan multinational conglomerate is the largest employer of the private sector in Sri Lanka.', 'http://www.hayleys.com/templates/main/images/logo.jpg', ',EE,', 26, 36, 'EE Seminar Room', '0710820599', '0710811668', 1, 29, ''),
('Diesel & Motor Engineering PLC', 'DIMO', 'DIMO Technology -"Expect Perfection" refers to the brand promise that all employees at DIMO and the world-class solutions that we provide, abide by. It is the promise to deliver the best or nothing, be it a product, service or a complete packaged solution. In delivering the best or nothing, we agree to adhere to our values and ethics, and promise what is truly deliverable. Hence, our TECHNOLOGY is unique -"The way we do things"ÃÂ. And that creates a benchmark to achieve perfection in all our customerÃÂs'' minds.\r\n\r\nDIMO has long been committed to responsible and ethical business strategies geared to creating corporate value. Representing world''ÃÂs first-in-class brands, we bring the latest technologies and solutions to our customer''ÃÂs doorstep. Having started out in the automotive industry, DIMO''s businesses have extended to an array of engineering sectors. Our employees affectionately known as the "DIMO Tribe" are the foundation for our enduring strength and ultimately our success.', 'http://www.areyouready.uom.lk/images/rur/dimo.jpg', ',EE,ENTC,MECH,CE,TLM,', 27, 50, 'ENTC1', '0717260366,0718538813', '0777857447', 1, 50, ''),
('K D A Weerasinghe Co (PVT) Ltd', 'KDAW', 'K. D. A. Weerasinghe and Co. (KDAW), is one of the largest engineering and contracting firms in Sri Lanka. A leading provider of diverse technical and professional construction services, KDAW undertakes large projects in the fields of Road, Building, Bridge and Airport Construction as well as Water Supply and Drainage, Irrigation, Land Drainage and Storm Water Drainage. K. D. A. Weerasinghe and Co.''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs performance has been strongly commended by clients such as Road Development Authority Sri Lanka, National Water Supply and Drainage Board, Airport & Aviation Services [SL] Limited, Josef Riepl (JR), Sumitomo Corporation and consultants such as Lahmeyer International, Japan Air port Consultants, Engineering Science Inc, Mott MacDonald''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs, SMEC & URS.', 'http://www.kdaw.lk/images/logo.png', ',ME,MECH,QS,', 28, 24, 'ME Final Year Room', '0715507040', '0717657774', 1, 24, ''),
('Co-Energi (Pvt) Ltd', 'coenergi', 'Co-Energi (Pvt) Ltd, a Joint Venture with Vidullanka PLC, is set up to promote energy conservation among Sri Lankan and regional businesses. It is offering energy efficiency consultancy for buildings and industrial processes leveraging experienced team and hands on knowledge to meet specific local industry needs to save and be sustainable. Our team of consultants and engineers work with the client''s technical and management team, the project team and consultants/contractors to assess the business requirements and deliver appropriate solutions.', 'http://www.co-energi.com/images/logo.jpg', ',EE,MECH,', 29, 36, 'MELR 3', '0715507040', '0715499235', 1, 36, ''),
('Warna Exporters (Pvt) Ltd', 'Warna', 'Warna Exporters are a leading Sri Lankan Manufacturer of household and industrial wooden brush ware. With worldwide export capabilities, employing the latest technology to produce high quality products with strict quality control procedures, Warna Exporters are perfectly equipped to supply your brush ware needs. Starting out as a small 10 man team of employees, Warna has grown to a 150 strong work force in 12 years.\r\n\r\nWarna Exporters have the capabilities to fully manage the production process from tree cutting and preparation through to filling and shipping orders to customers around the globe. Timber blocks are produced from plantation grown FSC certified rubber wood, and can be filled with a variety of natural fibers or synthetic materials if required. \r\n\r\nWarna Exporters have the experience necessary to supply both branded and own brand products made to customers specifications as well as having the ability to design and provide merchandising cartons & packaging to meet the varied demands of today''s world wide markets. ', '', ',CE,EE,', 30, 18, 'EE Lec Room 1', '0710820599', '0775128918', 1, 18, ''),
('MilleniumIT', 'MIT', 'Technology is only as good as the people who build it. At MillenniumIT, we know that people are our greatest asset.\r\n\r\nWe hire the best, so you get to work with the best. We provide first-rate facilities for continuing development, sports and recreation, and for helping our people maintain a healthy work/life balance.\r\nWe also offer internships to promising young people considering careers in our field.\r\n\r\nAnd as you would expect from a technology company, we run a real-time, effectively paperless enterprise in a virtual space where geographical separation between offices and work sites no longer matters. What does matter to us is our commitment to our employees and our customers alike. Where real-time meets the real world, real people matter the most.', 'http://www.areyouready.uom.lk/images/rur/mit.jpg', ',CPE,CE,CSE,EE,IT,MECH,ENTC,ERM,', 31, 108, 'IT Room next to Audi', '0715779877,0772980726', '0715633436', 1, 108, ''),
('Brandix Lanka Ltd', 'brandix', 'The Brandix Way of Life is our culture and permeates our whole organisation. The Brandix corporate ''personality'' is determined by three overlapping areas: values, work culture and social responsibility. Our way of working is all about accepting and embracing our values, and acting with social responsibility. It''s also about a young and dynamic entity which supports its personalities to blossom in a vibrant environment.\r\n\r\nAn organisation is the sum of the people it employs.\r\nThe Brandix culture not only aligns associates with corporate goals, it moulds their philosophy of work and therefore life. Changing mindsets positively takes great care and time but its value is inestimable. As well as encouraging associates to becoming customer-focused, incorporating speed, flexibility, innovation and passion into their work allows them to think more productively and perform for results.', 'http://www.areyouready.uom.lk/images/rur/brandix.jpg', ',CPE,CSE,IT,FD,ME,MECH,TC,', 32, 80, 'TM Auditorium', '0715297460', '0717968497', 1, 80, ''),
('Sanken Construction (Pvt) Ltd', 'sanken', 'We, at Sanken Construction (Pvt) Ltd., are a team committed to provide a quality products and services at an affordable price and on time, in the execution of construction projects and in the manufacture of related products, with the support of our valuable suppliers and in total harmony with the society and the environment.\r\n\r\nWe are further committed, to satisfy our customers whilst improving the quality of life of our people and thereby improving the viability of our organization.\r\n\r\nWe value team work, efficiency, responsibility and responsiveness to achieve these goals, through optimization of resources and continual improvements of our systems at all levels of operation to further enhance the quality of our products & services.', 'http://sankenconstruction.com/images/sanken/logo.png', ',CE,EE,MECH,QS,', 33, 60, 'CE 302', '0713601629', '0716066399', 1, 60, ''),
('Lanka Electricity Company (Pvt) Limited', 'leco', 'Lanka Electricity Company Private Limited is a Company incorporated in 1983 for the purpose of electricity distribution in Sri Lanka.  The formation of the company is by acquiring assets of local authorities to create a modern and efficient distribution network.  This objective is achieved even above the expectations when evaluated after 29 years of operations.  The company has throughout attracted foreign funding from the Asian Development Bank and is highly benefited by the consultancies of utility consultants such as Becca Worely International in setting up their efficient network.  LECO as a utility is benchmarked very high in the South East Asian region.', 'http://leco.lk/wp-content/uploads/2012/08/leco_logo32.png', ',EE,', 34, 18, 'EE Board Room', '0710820599', '0711538675', 1, 18, ''),
('Nestle Lanka PLC', 'nestle', 'There is more to life at Nestle! Our commitment to enhance the quality of life everywhere, every day is as strong today as it was when we began our business. We characterize our company with a caring and human personality and work together as One Team with One Goal to achieve all our targets.\r\n\r\nWe believe in inspiring lives and increasing well-being, all of which begins with our people. Thus, we ensure that we put people before systems, and integrity before everything. Our values shape the standards we expect from our employees and the experience we offer our customers. Fulfilled employees create satisfied consumers. This simple belief has inspired us to create an environment that puts the emphasis on individual responsibility, opportunity and autonomy. We combine the scope and brand strength of a global company with the creativity and knowledge of a local business. As a result, people can have a far-reaching influence every day and explore their full long-term potential, propelled by continual support and a collaborative approach. However, true fulfillment comes from making your own opportunities -ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ through your ideas, energy and expertise.', 'https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcTx1A1dyr96z4Oe9gBOw8cRzQ0XhBwGwGhToHIi8kTHfn1P6jbl', ',CPE,CSE,EE,FM,MECH,TLM,', 35, 36, 'CSLB 16/19', '0770460887', '0713568613', 1, 36, ''),
('hSenid Mobile Solutions (Pvt) Limited', 'hsenidmobile', 'hSenid Mobile Solutions is a multi-national Telco-Mobile Software Solutions provider catering primarily to the Telecom and Financial markets across the globe. For over a decade hSenid Mobile has been at the forefront of innovation in providing dynamic wireless applications and back-end integrations that has evolved into a Next Generation Telco Platform converging Messaging, Mobile-Money, Operations/Business Support Systems and Core-Signalling.\r\n\r\nBeing a part of the Group, hSenid Software International (www.hSenid.com), hSenid Mobile has gained global recognition in providing dynamic wireless applications and back-end integrations for Telecommunication and Enterprise markets. The company carries out its operations from Singapore, Malaysia, United States, Latin America, India and Sri Lanka establishing a strong presence.\r\n\r\nSince its inception in 1997 hSenid Mobile has developed unique skills by concentrating exclusively on the requirements of people on the move. As mobile operators and financial institutions roll-out new services on mobile devices, hSenid has increasingly become the partner of choice to supply ''secure, convenient, state of the art applications built on an open and extendable Service Delivery Platform that fully leverages its customers'' investments in next generation services.\r\n\r\nThe hSenid product range, known as mChoice, is a complete mobile application infrastructure enabling a world of mobile experiences. mChoice addresses all the elements of the mobile Internet value chain from Next Generation SDP, to Recharge/Topup Solutions, Rewards and Churn Management Solutions, Location Based Services, USSD Gateway to various VAS platforms. The innovative nature of hSenid''s mobile solutions enables the creation of increased value, improved service quality, greater convenience, and better operational efficiency for operators and financial institutions.', 'http://www.hsenidmobile.com/templates/hsenid_mobile/images/hms_logo.jpg', ',CSE,EE,ENTC,IT,', 36, 50, 'IT Lec Room', '0715779877,0772980726', '0717673029', 1, 34, ''),
('Vidullanka PLC', 'vidullanka', 'Joining Vidullanka means, you will become an integral part of the emerging team, and will get ample opportunities to enhance your knowledge and gain valuable exposure.\r\nExperience with Vidullanka, is for those who believe in themselves - who are willing to work in an organization that thrives to succeed, for those with  dreams and passion to succeed \r\nVidullanka is  a company with a principal focus on growth and are dedicated in the fields of Hydro, Wind, Biomass, Solar and Construction.  As such we are always searching for creative people who are willing join the team. A career at Vidullanka connects an employee to a challenging yet inspiring experience. \r\n\r\nAs a team member at Vidullanka, you will be working together with some of the experienced & leading consultants in the country. The opportunity for growth at Vidullanka is considerable, due to our involvement in diverse project in renewable energy. \r\n\r\nWe are committed to develop the communities we work in, and to protect our natural environment.', 'http://lk.duinvest.com/mubasherFileServer/File.Company_Logo/Vidullanka%20PLC_company_logo.jpg', ',CE,', 38, 18, 'CE 208', '0713601629', '0719931136', 1, 18, ''),
('Piramal Glass Ceylon PLC', 'piramal', 'At Piramal Glass, we strongly believe in building appreciable ''human assets''. The best way to do that is by inspiring and engaging people through well-planned HR systems, based on global best practices and people processes.\r\n\r\nOur HR Vision is "To become "The Most Preferred" employer by empowering our employees and encouraging innovation and entrepreneurship in an environment that makes work fun."\r\n\r\nWe strive to achieve our vision by attracting, developing, and retaining people in an environment of high performance and continuous learning.\r\n\r\nPiramal Glass provides its employees with an exciting work environment, the freedom to implement innovative ideas and opportunities for cross-functional learning.', 'http://www.piramalglassceylon.com/templates/piramal-template/images/002piramallogo.gif', ',CPE,EE,ENTC,MECH,TLM,', 39, 13, 'CHE 3', '0714845315', '0719496774', 1, 13, ''),
('United Tractor & Equipment (Pvt) LTD', 'UTE', 'United Tractor & Equipment (Private) Limited, also known as UTE, provides engineering solutions to all Sri Lankan industries. Being the sole business superbrand contender in the ''general machinery'' category highlights that there is no single company that can provide such a vast array of machinery. The UTE is active in the following markets: 1. Construction Machinery, 2.Power Generation, 3.Material Handling and Storing, 4.Welding Equipment and Engineering Solutions\r\n\r\nApart from these mainstream markets, UTE''s biggest strength is its superior product support, hence the tagline "The journey continuesÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¦ long after the sale".\r\n\r\nCaterpillar features prominently in all these markets, showing the obvious synergy created by the unique CAT/Dealer relationship.', 'http://www.ute.lk/templates/united_tractors_static_page/images/logo.png', ',EE,MECH,', 40, 18, 'NCSLB', '0715507040', '0752213803', 1, 18, ''),
('Integrated Systems Development Ltd', 'ISDltd', 'Vibrant multitasking Electronic Hardware/Software Engineers are required for a rapidly growing European/Sri Lankan Research, Development and Manufacturing Company. \r\n\r\nIntegrated Systems Development Ltd (ISD Ltd) is a bespoke embedded solution provider,delivering end to end enterprise grade solutions encompassing ground-up custom hardware/software designs, embedded system design, distinctive algorithms, medical equipment, payment and retailing applications to global blue chip clients. \r\n\r\nThe R&D and manufacturing facilities are based in the Biyagama BOI zone. \r\n\r\nISD are contracted by global giant Origio a/s (member of Cooper Surgical Group) to design,develop, manufacture and supply their next generation IVF (In Vitro Fertilisation) medical equipment. To this end an urgent requirement exist for vibrant hardware/software engineers to partake in medical R&D projects. \r\n\r\nCandidates should hold outstanding academic grades as well as a real passion for the electronics/software industry and a natural ability in engineering. Precedence will be shown to candidates demonstrating exposure to the electronic/software industry form an early age. \r\n\r\nAn excellent remuneration package awaits candidates who meet our criterion.', 'http://isd-limited.com/wpimages/wpa9e16aa5_05.jpg', ',ENTC,', 41, 0, 'None', '0715465178', '0000000000', 1, 0, ''),
('Softlogic Information Technologies (pvt) Ltd', 'softlogic', ' A modest computer software company in the beginning with a vision to be the most preferred IT partner for corporate Sri Lanka. Today Softlogic Information Technologies is hailed as one of the pioneers and innovators of the information technology in Sri Lanka.\r\n\r\nIndeed, the company is currently the leading importer of personal computers to Sri Lanka. It also markets and distributes notebook computers, servers, storage, network infrastructure and printers. It looks to provide the world''s best products and services to its customers, while consolidating its market leadership.\r\n\r\nProviding the world''s best products and services to our customers, while consolidating our market leadership, we have established key relationships with the above global brands.\r\n', 'http://www.softlogic.lk/posters/130423130410logo.jpg', ',CSE,ENTC,IT,', 42, 18, 'IT Lec Room', '0715779877,0772980726', '0711443049', 1, 11, ''),
('SriLankan Airlines Ltd', 'srilankan', 'SriLankan Airlines, the National Airline of Sri Lanka, is an award winning carrier with a firm reputation as a global leader in service, comfort, safety, reliability, and punctuality.\r\n\r\nLaunched in 1979, SriLankan is currently expanding and further diversifying its wide range of products and services in order to drive the country''s ongoing boom in tourism and economic development.\r\n\r\nThe airline''s hubs are located at Bandaranaike International Airport in Colombo and Mattala Rajapaksa International Airport, Hambantota providing convenient connections to its global route network of 65 destinations in 35 countries in Europe, the Middle East, South Asia, Southeast Asia, the Far East, North America, Australia and Africa.\r\n\r\nSriLankan has a global workforce of approximately 5,900 employees in Sri Lanka and overseas. The airline has strong training programmes in all aviation related fields, in order to cater to its own expansion and the constant need to replace its staff, in high demand by other airlines.\r\n\r\nSriLankan Engineering is a provider of choice in Maintenance-Repair-Overhaul (MRO) activities in the region, with its strong expertise in Airbus aircraft, excellent facilities, and experienced engineering personnel.\r\nSriLankan Engineering possesses the prestigious EASA 145 certification for aircraft maintenance and its training facility has the EASA 147 certification from the European Aviation Safety Agency. \r\n\r\nFor information visit www.srilankan.com/mro', 'http://www.srilankan.com/images/logo.png', ',CE,EE,ENTC,FM,IT,MECH,QS,TLM,', 43, 60, 'CSE Lec. Room', '0710820599', '0778430603', 1, 60, ''),
('CodeGen International (pvt) Ltd', 'codegen', 'CodeGen are a market leader in delivering solutions, and with HLML5 and GWT in development for the ultimate dynamic on-line experience, the company maintains the strength of these solutions with active R&D, as well as on-going feasibility studies dedicated solely to emerging technologies. \r\n\r\nWith its multi-lingual, multi-company and multi-currency capabilities, and range of booking flows that include Dynamic packaging, packaged, shopping cart, and the REVOLUTIONARY Wide Search, TravelBox provides a unique end-to-end work flow that automates the traditional business processes and delivers high efficiency and increased profitability.\r\n\r\nThe well-established Enterprise version of TravelBox has been successfully deployed to some of the largest operators in the industry and is the platform on which a single repository store for all allocated inventory can be created, providing cross-sell, up-sell, dynamic packaging and dynamic pricing capabilities. TravelBox''s modular concept and the extensive product suite includes catering to complex auto pricing of multitude of inventory items such as Flights, Hotels, Packages, Cars, Transfer, Rail, Tours and Cruise whilst also recognizing the need for a generic product loader module for supporting ad-hoc inventory items specific to a particular business model. ', 'http://comp.ee/image/cache/data/manufacturers/codegen_logo-700x500.jpg', ',CSE,EE,ENTC,IT,TC,', 44, 48, 'ERM Lec. Room (As5)', '0714155561', '0777990611', 1, 41, ''),
('Amba Research', 'amba', 'Amba analysts are the source of our competitive advantage ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ our success stems from our ability to attract, train, mentor and retain the best available talent in investment research.\r\n\r\nOur hiring process includes stringent screening at every stage. As a result, our selection ratio (number of candidates chosen over those screened) is one of the lowest in the industry. We evaluate candidates on various parameters ranging from knowledge of capital markets and finance, attention to detail, written and verbal communication, numerical skills, customer orientation and teamwork.\r\n\r\nAmba analysts are MBAs, Chartered Accountants, Engineers, CFAs and PhDs. These talented individuals then undergo our extensive foundation course, which is recognized as best in class. AmbaÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs 10-day Equity Investment Analyst Training Program has received accreditation to account for 40 Continuing Education credit hours as part of the CFA Approved-Provider Program.\r\n\r\nOur Continuous Education Program (CEP) covers sectors, asset classes, and modeling best practices, to stay abreast of latest ideas, reinforce essential skills and stay current with the latest developments in investment research.\r\n\r\nOur ongoing, on-demand training programs in sector/industry research have also been validated by professional organizations such as ACCA (UK) and CIMA (UK), the latter having accredited us as a Continuous Professional Development partner.\r\n\r\nThe best validation has come from our clients ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ¢ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂ one of the largest global banks uses Amba to assist with their in-house analyst-training program.\r\n', 'http://www.ambaresearch.com/sites/default/files/ambaresearch_logo.png', ',EE,ENTC,IT,MECH,', 45, 18, 'CSLB 6', '0770460887', '0775481350', 1, 18, ''),
('Hemas Manufacturing (PVT) Ltd', 'hemas', 'Hemas acts as a contract manufacturing partner in the development and manufacture of FMCG products for several leading companies. The efficiency of superior manufacturing processes, developed over 60 years along with the International Product Quality and Safety Standards observed is evident in the high quality of personal care products manufactured by Hemas.\r\n\r\nManaged by cross-functional teams, the ISO and GMP certified manufacturing facilities at Dankotuwa, Sri Lanka, offer cost effective solutions for international clients. A manpower planning system, effective employee relations management, Japanese 5-S system and the Kaisen systems and constant training & development, helps the factory maintain constant & high standard in quality of production.\r\n\r\nHemas undertakes manufacturing of personal care products such as creams & lotions, toothpaste, shampoos, talcum powder, colognes, soap, baby diapers and feminine hygiene products. Hemas also undertakes private label manufacturing for international brands for these products.', 'http://www.hemas.com/images/logo.gif', ',CPE,', 46, 15, 'CHE 1', '0714845315', '0717363579', 1, 15, ''),
('Avery Dennison Lanka (PVT) Ltd', 'avery', 'Avery Dennison is a $6.3 billion company with more than 30,000 employees, and facilities in 60 countries that develop, manufacture and market a wide range of products for the retail and industrial supply chains. The Printer Systems Division does business with more than 90 of the top 100 U.S. retailers, and many of the leading apparel brands, as well as leading companies in virtually every type of business.\r\n\r\nOur Printer Systems Division - formed by combining Paxar''s Supply Chain Solutions group and Avery Dennison''s Printer Systems Worldwide Division - is here to provide you with products, services and processes that will benefit your business. The division combines manufacturers of Monarch and Avery Dennison brand barcode, pricing, merchandising, and RFID tickets, tags and labels; in-plant, in-store and distribution center printers, RFID printer/ encoders, labelers, and portable printers as well as the globally recognised Monarch brand handheld labellers and labels used for price-marking, inventory control, date coding and food rotation but these are only a portion of the offerings. Monarch services include consultative and repair professionals, systems integration and data management capabilities.', 'http://rbis.averydennison.com/content/dam/averydennison/rbis/global/en/images/Home/Logo/RBIS-Logo-290x45.png.avdimg.mh.55.mw.290.png.avdimg.mh.55.mw.290.png', ',CPE,CSE,TC,', 47, 18, 'CHE 2', '0714845315', '0716181154', 1, 18, ''),
('WSO2 Lanka (PVT) Ltd', 'wso2', 'Team WSO2 consists of experts in their respective domains, who have helped define numerous Web service standards and norms which are widely used today such as XML, SOAP, Apache Axis/ Axis 2, Apache Synapse, WSDL and much more. WSO2 has also been involved in welfare projects such as the Sahana project, which is now the world''s leading disaster management system.\r\n\r\nWe are motivated by passion for work, driven by a free, open and collaborative company culture that centers on client satisfaction and integrity. The glory and success of WSO2 invariably lie on the fact that it has been nourished by the best-of-breed experts from its humble beginnings to this day. \r\n\r\nAll WSO2 products are 100% open source and released under the Apache License Version 2.0. Contributing to key international standards organizations and foundations such as W3C, OASIS, OpenID Foundation, Infocard Foundation, Microsoft''s Interop Vendor Alliance, AMQP Working Group, oCERT, and Cloud Security Alliance, we possess the critical skills and experience to competently manage your problems in an open and transparent environment.   ', 'http://www.coloandcloud.com/wp-content/uploads/2012/06/762791717WSO2pic.jpg', ',CSE,EE,ENTC,IT,', 48, 30, 'IT Lec Room', '0715779877,0772980726', '0774553167', 1, 25, ''),
('D.S.Engineering Company', 'DSEngineering', 'Our journey so far was an uphill task, but today we can look back with utmost pride and satisfaction of our rewarded journey which resulted in a throng of prestigious corporate and individual customers around us. Our success was not due to any providence or luck but, due to sheer dedication and unparalleled services we have rendered to our clientele.\r\n \r\nOur profile is rich with a band of dominate customer who have sought our services for the customized services for their factories, hotels, hospitals, super markets, banks and show rooms so on and so forth.\r\n \r\nWe have come along way I a short time, still we are not proud but humble. Our mission will be accomplished once we become the undisputed leaders of the industries it is not a wishful thinking as we are armed with necessary pre requests to achieve it.\r\n \r\nOur unsurpassed accomplishments have contributed to manufacture oh HVAC products leadership through experience, technology and the capability to meet or exceed our customer''s exacting specifications.\r\n \r\nD. S. Engineers focusing on customer requirements with dependable & affordable solutions and all our materials and workmanship in each products group are fully guaranteed. ', 'http://dsengineering.lk/images/Ds_engineering_company_trademark.jpg', ',MECH,', 49, 18, 'MELR 2', '0715507040', '0717082182', 1, 17, ''),
('Intenational Construction Consortium (PVT) ltd', 'ICC', 'ICC is today a LEADING SRI LANKAN GENERAL CONTRACTOR with multi sector capability. Established in 1980, ICC today has SEVEN MAIN DIVISIONS \r\n\r\n(1) PROJECTS DEVELOPMENT DIVISION (To handle Development Projects either on its own or in Joint Venture with both Local and Foreign Collaborators on turnkey basis or otherwise), \r\n\r\n(2) AN INFRASTRUCTURE DEVELOPMENT DIVISION to undertake the construction of Power Stations, Fishery harbours, Irrigation structures etc., \r\n\r\n(3) A BUILDING CONSTRUCTION DIVISION (To handle high-rise buildings, Shop and Office Complexes and other commercial buildings, factories, warehouses, housing complexes, etc.), \r\n\r\n(4) A WATER SUPPLY & SANITATION DIVISION, \r\n\r\n(5) ROAD AND BRIDGE CONSTRUCTION DIVISION \r\n\r\n(6) A PROPERTY DEVELOPMENT DIVISION and its latest addition the\r\n\r\n(7) INTERNATIONAL DIVISION to undertake the construction work overseas.\r\n\r\nICC, apart from its CONSTRUCTION capability, owns and operates the following UNITS which are complementary to the Construction Industry (a) A READY MIX CONCRETE MANUFACTURE & SUPPLY UNIT (b) A PRESTRESSED AND PRECAST CONCRETE YARD, (c) QUARRY AND CRUSHER Operations, (d) A JOINERY WORKSHOP (e) ASPHALT CONCRETE MANUFACTURING AND SUPPLY UNIT and (f) CONCRETE BLOCK PRODUCTION UNIT\r\n\r\nFor more info follow \r\nwww.icc-construct.com/web/about-us.html \r\nwww.icc-construct.com/web/careers.html\r\n', 'http://www.icc-construct.com/web/images/stories/logos.jpg', ',CE,EE,MECH,QS,', 50, 50, 'Madanjeet Center', '0718767330', '0774196539', 1, 50, ''),
('IFS R&D International (Pvt) Ltd', 'IFS', 'IFS, the global enterprise applications company, develops,supplies, and implements IFS Applications, a component-based extended ERP software suite built on SOA technology. A public company (OMX STO: IFS) founded in 1983, IFS focuses on agile businesses where any of four core processes are strategic: service & asset management, manufacturing, supply chain and projects. The company has more than 2,000 customers and is present in 50 countries with 2,700 employees in total.\r\n\r\nIFS has been operating in Sri Lanka since 1997, and is one of the leading software development companies in the country with over 700 IT professionals working with the development and support of IFS ApplicationsÃÂÃÂ¢ÃÂÃÂÃÂÃÂ¢. Building upon the core values of professionalism, commitment, and simplicity, IFS is a nonhierarchical, team-oriented organization that offers career stability, scope for success, challenging work, excellent training, and international exposure, within an informal working environment. At IFS we believe that our employees are our most valuable assets and we are proud of our culture based upon the core values of professionalism, commitment, and simplicity. Our work environment fosters innovation and creativity and we maintain a healthy work-life balance.\r\n', '', ',CPE,MECH,TLM,', 51, 36, 'ARCHI 3rd floor', '0758260680', '0777105178', 1, 36, ''),
('Mobitel Lanka (Pvt) Ltd', 'mobitel', 'Sri Lanka Telecom Mobitel consistently sets standards of service considered to be the benchmark in the telecommunication industry. Hence, we are keen to get the best people on board.\r\n\r\nMobitel employees have the right skills, positive and friendly attitudes and a passion to serve our valued Customers.\r\nAbout our employees and working environment at Mobitel:\r\n\r\nCommunication with Staff:\r\nMobitel''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs first name basis and open door culture ensures that all employees can provide feedback to anyone in our senior management teams.\r\n\r\nDress Code:\r\nMobitel''ÃÂÃÂÃÂÃÂÃÂÃÂÃÂÃÂs minimum standard of an acceptable dress code is as follows:\r\nMonday-Friday: Smart, suitable for a professional business environment\r\n\r\nEmergency medical care:\r\nWe have trained and competent staff to administer first aid assistance in any emergency.\r\n\r\nMobitel Club:\r\nThe social and recreational events for our staff are organized by the Mobitel Club. The entire Mobitel staff automatically becomes member of the Mobitel Club upon commencement of employment. The Mobitel Club is run by an elected committee of staff members.', 'http://www.areyouready.uom.lk/images/rur/mobitel.jpg', ',ENTC,', 52, 18, 'ENTC Conference Room', '0717260366,0718538812', '0777979537', 1, 18, ''),
('Premium International (Pvt) Ltd', 'premium', 'The employees at Premium International are a group of enthusiastic, highly motivated skilled people. The work environment is lively and fun whilst maintaining professionalism.\r\n\r\nIn addition to exceptional skills and accomplishments we value integrity, honesty, reliability, and maturity. We seek smart, innovative, hardworking individuals who are good team players and effective decision makers. Our employees should be productive and maintain a solid work ethic.\r\n\r\nWe''re constantly looking for people who have a high synergy between attitude and aptitude. ', 'http://www.premium.lk/images/index_02.jpg', ',ENTC,', 53, 13, 'ENTC PG Room', '0717260366,0718538815', '0717321521', 1, 7, ''),
('Central Engineering Consultancy Bureau', 'cecb', 'CECB is a challenging and diverse organisation. We are always looking for gifted, motivated individuals for technical, consulting, and business management roles in all parts of the firm, in all parts of the world.\r\n\r\nIf you are considering your future and are looking for somewhere to make a real difference, CECB has much to offer.', 'http://www.sairt.com/images/clients/cecb-4-page.jpg', ',CE,', 54, 15, 'CERC 302', '0716753144', '0716520206', 1, 15, '');
INSERT INTO `company` (`name`, `shortName`, `description`, `logo`, `fields`, `id`, `capacity`, `building`, `buildTel`, `tel`, `panels`, `assigned`, `undergrads`) VALUES
('State Development & Construction Corporation', 'sdcc', 'Vision\r\n\r\nTo be the best infrastructure development and construction organization, providing value for money for the Nation by 2012.\r\n\r\nMission\r\n\r\nTo, assist economic development of the country, by participating in national infrastructure development and other construction activities and carrying out such activities to the highest standards of quality and be the market leader in the civil construction industry and in the production of heavy reinforced and pre-stressed concrete members in the pre-cast concrete industry.', 'http://sdcc.lk/templates/jv_zuni//images/blue/logo.png', ',CE,', 55, 30, 'Madanjeet Center', '0718767330', '0714820814', 1, 30, ''),
('Associated Battery Manufacturers ( Ceylon ) Limited', 'ABM', 'Associated Battery Manufacturers (Ceylon) Limited (ABM) is the largest manufacturer of Lead Acid Batteries in Sri Lanka. ABM was established in 1960 in technical collaboration with British Batteries, and emerged as a blue-chip company due to the high quality products manufactured. Currently we maintain No.1 position in Sri Lanka while exporting batteries to several countries.\r\nABM produces both "dry charged" and "maintenance free" batteries under the well recognized brand names "Exide", "Lucas" and "Degenite". In addition to the automotive and motor-cycle lead acid batteries, ABM also produces deep cycle batteries for solar systems. Deep cycle batteries are produced to suit the tropical climate for trouble free use as they are used in remote villages. Few years back, ABM entered into the international market exporting batteries. The export statistics increased gradually year by year. The performance of ABM in the last few years has been remarkable. As an appreciation for this commendable performance, the company has been widely recognized by the community.\r\n', '', ',MECH,', 56, 18, 'MELR 2', '0715507040', '0711267766', 1, 18, ''),
('Fonterra Brands Lanka', 'fonterra', '(FOR MANAGEMENT TRAINEE).\r\n\r\nFonterra Co-operative Group Limited is a New Zealand multinational dairy co-operative owned by almost 10,500 New Zealand farmers. The company is responsible for approximately 30% of the world''s dairy exports and with revenue exceeding NZ $19.87 billion, is New Zealand''s largest company.\r\n\r\nFonterra was formed in 2001 from the merger of the two largest co-operatives, New Zealand Dairy Group and Kiwi Co-operative Dairies, together with the New Zealand Dairy Board, which had been the marketing and export agent for all the co-operatives. Fonterra effectively has monopsony control of the New Zealand domestic and export dairy industry.\r\n\r\nSupporting our farmers, we have 16,000 passionate people in New Zealand and around the world working to make dairy available to millions of consumers in 140 countries every day.\r\n\r\nTogether with our Shareholders, the Fonterra team produces more than two million tonnes of dairy ingredients, specialty ingredients and consumer products each year and 95 per cent of these are exported to a world wanting more and more of the nutritional benefits we offer.\r\n\r\nIt''s this passion that is reflected in our vision to share dairy with the world. Around the world we want our customers to think ''Fonterra'' first when they think dairy. In our branded markets we want our consumers to have our brands top-of-mind as the leaders of dairy. If we achieve this we will have achieved our vision of being the natural source of dairy nutrition for everybody, everywhere, every day. Its'' a bold goal, but it''s grounded in reality. We have what it takes. \r\n\r\n', 'http://www.fonterra.com/wps/wcm/connect/ad937180-365b-48e4-8f1c-fb3f6061a753/logo.gif?MOD=AJPERES&CACHEID=ad937180-365b-48e4-8f1c-fb3f6061a753', ',ARCH,CPE,CE,CSE,ERM,EE,ENTC,FM,IT,FD,ME,MECH,QS,TC,TCP,TLM,', 57, 50, 'CSLB 16/19', '0770460887', '0718842397', 1, 50, ''),
('Motorola Solutions Lanka (PVT) Ltd', 'mototola', 'Motorola Solutions connects people through technology. Businesses and government agencies around the world turn to Motorola Solutions innovations when they want highly connected teams that have the information they need throughout their workdays and in the moments that matter most to them.\r\n\r\nAt Motorola Solutions, we strive to create an environment where every employee can contribute to his or her fullest potential. We do this through a set of common Values that bind us together. \r\n\r\nWe are innovative. We constantly create ingenious solutions to the real challenges of today, tomorrow and beyond. \r\n\r\nWe are passionate. We meet every challenge with energy and determination, always pursuing ever-higher standards. \r\n\r\nWe are driven. We keep it simple by focusing on what matters most so we can seize opportunities with speed and confidence. \r\n\r\nWe are accountable. We stand behind the work we do, the contributions we make and the high business standards we maintain. \r\n\r\nWe are partners. We succeed together because we respect all individuals and value contributions from colleagues and customers alike. \r\n\r\nEverything you''ll do at Motorola will be with the support of the top minds, tools and various Motorola Business Councils behind you. It''s how we connect a range of abilities and ideas within the organization to the progress we''re making outside of it. As we begin our new chapter as Motorola Solutions, our Business Councils are excited to shape their missions to support and grow our new business strategies.\r\n\r\n', 'http://www.motorolasolutions.com/web/Business/Resources/bms10/images/solutionslogo.png', ',CSE,ENTC,', 58, 18, 'ERM Lec. Room 1', '0714155561', '0715437866', 1, 17, ''),
('Lanka Sugar Company - Pelwatte', 'lankasugar', 'Pelwatte Sugar Industries PLC is the Sri Lanka''s largest manufacturer of sugar and other by-products from raw sugar cane. The Company manages a 2,700 hectare Nucleus estate and a Settlement estate of 3,500 hectares situated in the Moneragala District of the Uva Province. It became part of the DCSL Group following an acquisition of 47% stake in March 2011. \r\n\r\nIncorporated in 1981, Pelwatte Sugar Company Ltd. was converted from a Private Company to a Public Limited Liability the very next year and was first listed on the Colombo Stock Exchange (CSE) in 1984. In 1990, the company name was changed to Pelwatte Sugar Industries PLC and three decades on, Pelwatte Sugar Industries today operates Sri Lanka''s largest and most technologically-advanced sugar factory producing more than 22,000 MT of sugar every year. \r\n\r\nA Subsidiary Company, Pelwatte Sugar Distilleries (Pvt) Ltd. produces potable and technical alcohol utilizing molasses, a by-product of the sugar factory. The Company is the no.1 producer of potable alcohol in Sri Lanka, meeting requirements demanded by the liquor and cologne industries as well as the manufacturers of Ayurvedic and Western medicine in Sri Lanka. \r\n\r\nThe Group strongly believes in giving back to the country and plays an important and constructive role in the social development and the general upliftment of the people in its command areas. The Group directly employs about 6,000 workers in the area.', '', ',CPE,CE,EE,IT,MECH,', 59, 15, 'Madanjeet Center', '0718767330', '0777575877', 1, 15, ''),
('MAS Active-Linea Intimo (PVT) Ltd', 'masActive', 'MAS Active attires a wide spectrum of sportsmen and women, from amateurs to international sports celebrities, with the most technologically advanced performance enhancing sportswear. Within our short span of existence, we have become the fastest-growing supplier in the region of this highly competitive category. Established in 2005, to complement the already established apparel capabilities within the Group, MAS Active also manufactures premium men''s underwear. Our Customers include globally renowned brands such as Nike, Columbia and Ralph Lauren.\r\n\r\nAdding value to MAS Active''s offering is the specialist division ''Linea Intimo'', South AsiaÃÂÃÂ¢ÃÂÃÂÃÂÃÂs largest ''Seamless'' manufacturer. Linea Intimo is unique within MAS, being the only fully integrated unit, converting yarn to finished products under one roof. We are equipped with the state-of-the-art Italian Warp and Weft Knitting machines and fully automated rotary dyeing machines. Linea Intimo''s Customers include Lululemon, Nike and Oxylane. ', 'http://www.masholdings.com/resources/images/MAS-Holdings-Logo-Changing-Perspectives.png', ',CPE,CE,EE,FM,FD,MECH,TC,', 60, 24, 'TM Lec room', '0715297460', '0716366252', 1, 24, ''),
('Venora International Projects (PVT) Ltd', 'venora', 'Venora International Projects (Pvt) Ltd. is an Engineering Company. The Engineering Project Division was set up to offer Technical Support to the valued customers. From humble beginnings, We have gained considerable recognition in their respective fields of activity. We have 3 distinct categories of business.\r\n\r\n1.)Project Related - Electrical installation works, lighting, building management systems for Commercial, Industrial, Leisure sites and sport complexes etc.\r\n\r\n2.)Switch Board Manufacturing - We have fully-fledge switch board manufacturing facility with ample space and all required modern equipment and well experience staff to fabricate all kinds of electrical switch board.\r\n\r\n3.)Lightning, Surge Protection and Power Factor Correction Systems - We are the local representative for lightning and surge protection equipment of Cirprotec, Spain and also undertake all kinds of electrical grounding work. We are also agent for Power factor improvement equipment from AEG Germany. \r\n\r\n', 'http://builders.lk/uploads/s/Shahan-Builders.lk/cd1ebbb4ea.jpg', ',EE,', 61, 15, 'EE Final Year Room', '0710820599', '0718323297', 1, 15, ''),
('Geological Survey and Mines Bureau', 'Survey&MB', 'Vision\r\nTo be the premier national geoscience agency that generates and disseminates geoscientific information and regulates mining and processing of Sri Lanka''s mineral resources in the most sustainable manner.\r\n\r\nMission\r\nThe mission of the GSMB is to provide geoscientific information, advice and services to the policy makers and the community and to promote and manage the mineral resources of the country for economic development while ensuring environmental sustainability. It regulates exploration, extraction, value addition, transportation and trading of minerals.\r\n', 'http://static.squarespace.com/static/510527a4e4b0d2690e9b5cbb/t/51128925e4b022eb85f4b2d1/?format=500w', ',ERM,', 62, 36, 'MELR 3', '0715507040', '0726170392', 1, 36, ''),
('NCD Consultants (pvt) LTD', 'ncd', '(Special Attention: Structural Engineers Only). \r\n\r\nNDC provide technical consulting and installation services to the rail, road, utility and construction sectors.\r\n \r\nWe offer a comprehensive portfolio of Project Management, Survey, Installation, Design and IT-based expertise.  \r\n \r\nAt NDC we embrace technology to provide enhanced levels of quality and efficiency. All of our clients can expect a tailor-made solution to meet with their individual requirements.\r\n \r\nOur professional staff have years of experience within the transportation, utility and civil construction sectors, having worked on many of the largest network construction projects of recent times in Sri Lanka.', '', ',CE,', 63, 18, 'CE 124', '0713601629', '0712772368', 1, 18, ''),
('Aitken Spence PLC', 'aitkenspence', 'Aitken Spence PLC is a leading player in Hotels, Travel, Maritime Services, Logistic Solutions and Power Generation in Sri Lanka. The Colombo-based diversified conglomerate has significant interests in Plantations, Insurance, Financial Services, IT, Printing and Garments. \r\n\r\nOur core Human Resource strategy is to add value in all spheres of our activities by improving the potential of our employees and our business processes.  It is our objective to ensure that all Human Resource initiatives help deliver business results.\r\n\r\nCommitment to Service is at the very heart of Aitken Spence, giving nourishment to every aspect of its existence and future plans.  A nucleus of dynamic people who have translated this into business practices has led the Group on its continuing rise. This dynamism provides the energy to enable the Group to continue to build on its strong roots and maintain consistent growth, venturing globally with ambitious targets and achieving results.\r\nTherefore developing a culture and ethos of upward mobility is essential to keep our people factor in line with our vision.  \r\n\r\nConsequently, the conventional role of human resource management has evolved to take on the new mission of a business partner in the development of both self and organisation.', 'http://www.aitkenspence.com/images/aitken_spence_corp.jpg', ',CE,CSE,EE,FM,IT,FD,MECH,TC,TLM,', 64, 39, 'CSE Tutorial Room', '0710820599', '0724130822', 1, 39, ''),
('ISURU ENGINEERING (PTE) LTD', 'isuruengineering', 'IEL commenced its operations in 1993 with Chairman/Managing Director and a Director. A small Team of Engineers provided the support services at the inception. IEL received Membership of National Construction Association of Sri Lanka in January 1997.\r\n\r\nSince then it has undertaken Construction work in Sri Lanka and the Republic of Maldives. Through perseverance and dedication, and with the gradual build up of the Engineering team, it managed to rise to the highest ICTAD Grading within a short period of 4 years. Similarly upgrading was possible in the fields of Water Supply & Drainage, Highways and Bridge Construction. IEL has been admitted to the Dun & Bradstreet Global Database. IEL has been assessed and certified for meeting the requirements of ISO 9001-2000 by SGS, United Kingdom, and has reached a prime position in the construction field through its highly successful operations in Sri Lanka and abroad.\r\n\r\n\r\n\r\n', 'http://www.isurueng.lk/wp-content/uploads/2012/11/logo2.png', ',CE,', 65, 30, 'CERC 401', '0716753144', '0772455221', 1, 30, ''),
('EAM Maliban Textiles (PVT) Ltd', 'malibanTextiles', 'EAM Maliban is fully equipped with innovation to serve customer needs. 11 state of the art manufacturing units offers a range of manufacturing capabilities with facilities to handle the most complex operations and wet processing features. Best professionals in design, materials sourcing, production, Information technology as well as logistics. We also have a massive pool of high skilled and creative individuals. We leverage our business high to ensure that we can bring your business to a much higher level to achieve global competitiveness in terms of garment design and manufacture, at the same time offering consistent and cost effective results.\r\n\r\nDue to our continued expansion, we always need outstanding individuals who are looking for a career in the exciting and challenging world of Apparels. The company offers all employees a competitive and comprehensive employment package. If you believe you are an outstanding individual, with exceptional work ethic, we would like to meet you.', 'http://www.maliban.com/images/stories/logo.jpg', ',FD,TC,', 66, 15, 'CSLB 10', '0770460887', '0715858486', 1, 15, ''),
('National Engineering Research and Development Centre of Sri Lanka', 'NERD', 'NERDC became operational during the latter part of 1974 , with as its first chairman. The centre was located from a Small section of the Industrial Development Board complex at Katubadda Moratuwa, with the intake of support staff as engineers and clerical grades, subsequently the office was locates at a more space building at Gall roar. Colombo-03. In September 1978 office was shifted to present location of IDB Industrial Estate Ekala Ja-Ela.\r\n\r\nVISION\r\n \r\nTo be the premier Engineering Research and Development Centre in the country and to be able to make major contributions to the economic and social development of the people of Sri Lanka.\r\n \r\nMISSION\r\n \r\nTo engage in research and development activities that would have a direct bearing on the industrial development of Sri Lanka and on the improvement of the living standards of the people, and thereby develop technologies that would help in the sustainable utilization of her human and material resources towards the economic development of the country.\r\n', 'http://www.nerdc.lk/en/imgs/banner.jpg', ',CE,MECH,', 67, 18, 'Madanjeet Center', '0718767330', '0773515626', 1, 11, ''),
('Lanka Sporting Goods (PVT) Ltd', 'lankaSporting', 'Description Not Available...', '', ',ENTC,FD,TC,TLM,', 68, 36, 'CSLB 12', '0770460887', '0778468558', 1, 36, '');
