INSERT INTO `questions` (`indexNum`, `message`) VALUES
('080000A', 'asdasdasdasd'),
('090493R', 'GPA or Class is not an accurate measurement for recruiting high potential,innovative engineering graduates although not scored at exams. They are money makers for companies. What should be companies'' screening method not to lose them ? '),
('090230K', 'why don''t industry come before the last moment, liken involving the final year projects so that we get some industry touch as well as the industry get to know the people and could workout some projects for cheap labor "undergrads" :)');
